import com.alan.clients.value.Mode;
import lombok.Getter;
import net.minecraft.entity.EntityLivingBase;
import net.minecraft.network.play.client.C02PacketUseEntity;
import net.minecraft.network.play.client.C0APacketAnimation;
import java.util.List;
import java.util.concurrent.CopyOnWriteArrayList;

@Getter
@ModuleInfo(description = "Attacks entities for you", category = ModuleCategory.COMBAT, autoEnabled = true)
public class KillAura extends Module {
    public List<Mode> modes = new CopyOnWriteArrayList<>();

    public KillAura() {
        modes.add(new SingleTarget(this, "Single"));
        modes.add(new MultiTarget(this, "Multi"));
        modes.add(new SwitchTarget(this, "Switch"));
    }

    @Override
    public void onEnable() {
        modes.forEach(Mode::onEnable);
    }

    @Override
    public void onDisable() {
        modes.forEach(Mode::onDisable);
    }

    @EventLink()
    public final Listener<PreUpdateEvent> onPreUpdate = event -> {
        modes.forEach(Mode::onPreUpdate);
    };

    @EventLink()
    public final Listener<AttackEvent> onAttack = event -> {
        modes.forEach(mode -> mode.onAttack(event));
    };

    @EventLink()
    public final Listener<PacketSendEvent> onPacketSend = event -> {
        Packet<?> packet = event.getPacket();
        // Track swing packets for attack synchronization
        if (packet instanceof C0APacketAnimation) {
            // Swing occurred — track for rotation/aim backtrack
            SwingComponent.lastSwing = System.currentTimeMillis();
        }
    };
}

