package com.alan.clients.component.impl.player;

import com.alan.clients.component.Component;
import com.alan.clients.newevent.Listener;
import com.alan.clients.newevent.annotations.EventLink;
import com.alan.clients.newevent.impl.packet.PacketSendEvent;
import net.minecraft.network.Packet;
import net.minecraft.network.play.client.*;

public class BadPacketsComponent extends Component {
    private boolean attacked, swung, slotChanged, blockHit, inventoryOpened;

    @EventLink()
    public final Listener<PacketSendEvent> onPacketSend = event -> {
        final Packet<?> p = event.getPacket();

        if (p instanceof C02PacketUseEntity) {
            attacked = true;
        } else if (p instanceof C0APacketAnimation) {
            swung = true;
        } else if (p instanceof C09PacketHeldItemChange) {
            slotChanged = true;
        } else if (p instanceof C0DPacketCloseWindow) {
            inventoryOpened = true;
        }
    };

    public boolean bad() {
        return attacked || swung || slotChanged || blockHit || inventoryOpened;
    }

    public void reset() {
        attacked = swung = slotChanged = blockHit = inventoryOpened = false;
    }
}

