package com.alan.clients.module.impl.render;

import com.alan.clients.module.Module;
import com.alan.clients.module.api.Category;
import com.alan.clients.module.api.ModuleInfo;
import com.alan.clients.newevent.Listener;
import com.alan.clients.newevent.annotations.EventLink;
import com.alan.clients.newevent.impl.packet.PacketSendEvent;
import net.minecraft.network.Packet;
import net.minecraft.network.play.client.*;

@ModuleInfo(description = "Allows you to freely move the camera out of your body", category = Category.RENDER)
public class FreeCam extends Module {
    private double x, y, z;

    @Override
    protected void onEnable() {
        x = mc.thePlayer.posX;
        y = mc.thePlayer.posY;
        z = mc.thePlayer.posZ;
        mc.thePlayer.noClip = true;
    }

    @Override
    protected void onDisable() {
        mc.thePlayer.setPositionAndRotation(x, y, z, mc.thePlayer.rotationYaw, mc.thePlayer.rotationPitch);
        mc.thePlayer.noClip = false;
    }

    @EventLink()
    public final Listener<PacketSendEvent> onPacketSend = event -> {
        final Packet<?> p = event.getPacket();

        if (p instanceof C03PacketPlayer ||
            p instanceof C0APacketAnimation ||
            p instanceof C0BPacketEntityAction ||
            p instanceof C08PacketPlayerBlockPlacement) {
            event.setCancelled(true);
        }
    };
}
